                      && CountPositiveAfterDiv(a, d) >= CeilHalf(|a|)
  ensures d == 0 ==> (forall d' :: d' == 0 || CountPositiveAfterDiv(a, d') < CeilHalf(|a|))
{
  var n := |a|;
  var pcount := 0;
  var ncount := 0;
  var zcount := 0;
  var i := 0;
  while i < n
    invariant 0 <= i <= n
    invariant pcount == CountPositive(a[..i])
    invariant ncount == CountNegative(a[..i])
  {
    assert pcount + ncount + zcount == i;
    if a[i] > 0 {
      pcount := pcount + 1;
    } else if a[i] < 0 {
      ncount := ncount + 1;
    } else {
      zcount := zcount + 1;
    }
    i := i + 1;
  }
  assert pcount + ncount + zcount == n;
  var half := (n + 1) / 2;
  if pcount >= half {
    d := 1;
    CountPosDivPos(a, 1);
  } else if ncount >= half {
    d := -1;
    CountPosDivNeg(a, -1);
  } else {
    d := 0;
    forall d' | d' != 0
      ensures CountPositiveAfterDiv(a, d') < CeilHalf(|a|)
    {
      if d' > 0 {
        CountPosDivPos(a, d');
      } else {
        CountPosDivNeg(a, d');
      }
    }
  }
}

